// src/pages/Users.jsx
import { useEffect, useState } from "react";
import { fetchUsers, createUser, updateUser, deleteUser } from "../services/users";
import { useAuth, hasRole } from "../AuthContext";

const ROLES = ["ADMIN", "SALES", "ACCOUNTANT"];
const STATUSES = ["ACTIVE", "INACTIVE"];

function pickApiError(err, fallback = "Có lỗi xảy ra") {
    const d = err?.response?.data;
    // gom các kiểu trả lỗi thường gặp của Spring
    const details =
        d?.errors?.map?.(e => e.defaultMessage || e.message)?.join("\n") ||
        d?.fieldErrors?.map?.(e => e.defaultMessage || `${e.field}: ${e.message}`)?.join("\n") ||
        d?.violations?.map?.(v => v.message)?.join("\n") ||
        d?.message || d?.error || (typeof d === "string" ? d : "");
    return details || fallback;
}

export default function Users() {
    const { user } = useAuth();
    const isAdmin = hasRole(user, "ADMIN");

    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState({
        username: "",
        fullName: "",
        email: "",
        phone: "",
        role: "SALES",
        status: "ACTIVE",
        // password: "" // nếu BE cần khi tạo user
    });

    useEffect(() => {
        load();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [page]);

    async function load() {
        setLoading(true);
        try {
            const { rows, totalPages } = await fetchUsers({ page, size: 10 });
            setRows(rows);
            setTotalPages(totalPages);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
            alert(pickApiError(e, "Tải danh sách người dùng thất bại"));
        } finally {
            setLoading(false);
        }
    }

    function openCreate() {
        setEditing(null);
        setForm({
            username: "",
            fullName: "",
            email: "",
            phone: "",
            role: "SALES",
            status: "ACTIVE",
            // password: ""
        });
        setShow(true);
    }

    function openEdit(row) {
        setEditing(row);
        setForm({
            username: row.username || "",
            fullName: row.fullName || "",
            email: row.email || "",
            phone: row.phone || "",
            role: row.role || "SALES",
            status: row.status || "ACTIVE",
        });
        setShow(true);
    }

    async function onSubmit(e) {
        e.preventDefault();
        try {
            if (editing) {
                // UPDATE: chỉ gửi {fullName,email,phone,roleName,active}
                await updateUser(editing.id, form);
            } else {
                // CREATE: username + fullName + (email,phone,roleName,active[,password])
                await createUser(form);
            }
            setShow(false);
            await load();
        } catch (err) {
            alert(pickApiError(err, editing ? "Lưu người dùng thất bại" : "Thêm người dùng thất bại"));
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xoá người dùng "${row.username}"?`)) return;
        try {
            await deleteUser(row.id);
            await load();
        } catch (err) {
            alert(pickApiError(err, "Xoá người dùng thất bại"));
        }
    }

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Người dùng & Phân quyền</h2>
                    <p className="text-sm text-slate-500">Quản trị viên có thể quản lý người dùng</p>
                </div>
                {isAdmin && (
                    <button onClick={openCreate} className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                        Thêm người dùng
                    </button>
                )}
            </div>

            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Tên đăng nhập</th>
                            <th className="px-4 py-3 text-left">Họ tên</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-left">Điện thoại</th>
                            <th className="px-4 py-3 text-left">Vai trò</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr><td className="px-4 py-6" colSpan={7}>Đang tải…</td></tr>
                        ) : rows.length === 0 ? (
                            <tr><td className="px-4 py-6" colSpan={7}>Chưa có dữ liệu</td></tr>
                        ) : (
                            rows.map((u) => (
                                <tr key={u.id} className="hover:bg-indigo-50/40">
                                    <td className="px-4 py-3 font-medium">{u.username}</td>
                                    <td className="px-4 py-3">{u.fullName}</td>
                                    <td className="px-4 py-3">{u.email || "-"}</td>
                                    <td className="px-4 py-3">{u.phone || "-"}</td>
                                    <td className="px-4 py-3">{u.role}</td>
                                    <td className="px-4 py-3">
                      <span className={"px-2 py-0.5 rounded-full text-xs " + (u.status === "ACTIVE" ? "bg-emerald-100 text-emerald-700" : "bg-slate-100 text-slate-700")}>
                        {u.status}
                      </span>
                                    </td>
                                    <td className="px-4 py-3 text-right">
                                        {isAdmin && (
                                            <div className="inline-flex gap-2">
                                                <button onClick={() => openEdit(u)} className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                                <button onClick={() => remove(u)} className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xóa</button>
                                            </div>
                                        )}
                                    </td>
                                </tr>
                            ))
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2">
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50" onClick={() => setPage((p) => Math.max(0, p - 1))} disabled={page <= 0}>← Trước</button>
                <div className="px-3 py-1.5 text-sm">Trang {page + 1}/{totalPages}</div>
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50" onClick={() => setPage((p) => p + 1)} disabled={page + 1 >= totalPages}>Sau →</button>
            </div>

            {/* Modal */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-2xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing ? "Sửa người dùng" : "Thêm người dùng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShow(false)}>Đóng</button>
                        </div>

                        <form onSubmit={onSubmit} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            {!editing && (
                                <div className="md:col-span-2">
                                    <label className="text-sm text-slate-600">Tên đăng nhập</label>
                                    <input required value={form.username} onChange={(e) => setForm((f) => ({ ...f, username: e.target.value }))} className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                                </div>
                            )}

                            <div>
                                <label className="text-sm text-slate-600">Họ tên</label>
                                <input required value={form.fullName} onChange={(e) => setForm((f) => ({ ...f, fullName: e.target.value }))} className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Email</label>
                                <input type="email" value={form.email} onChange={(e) => setForm((f) => ({ ...f, email: e.target.value }))} className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Điện thoại</label>
                                <input maxLength={20} value={form.phone} onChange={(e) => setForm((f) => ({ ...f, phone: e.target.value }))} className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Vai trò</label>
                                <select value={form.role} onChange={(e) => setForm((f) => ({ ...f, role: e.target.value }))} className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" disabled={!isAdmin}>
                                    {ROLES.map((r) => <option key={r}>{r}</option>)}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select value={form.status} onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))} className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" disabled={!isAdmin}>
                                    {STATUSES.map((s) => <option key={s}>{s}</option>)}
                                </select>
                            </div>

                            {/* Nếu BE yêu cầu password khi tạo thì mở comment:
              {!editing && (
                <div className="md:col-span-2">
                  <label className="text-sm text-slate-600">Mật khẩu</label>
                  <input type="password" value={form.password||""} onChange={(e)=>setForm(f=>({...f,password:e.target.value}))}
                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                </div>
              )} */}

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button type="button" className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200" onClick={() => setShow(false)}>Huỷ</button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">Lưu</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
